SELECT p.id, p.prescription_no, p.register_id, p.pet_id, pet.name as pet_name, p.doctor_id, p.diagnosis, p.total_amount, p.status, p.remark, p.create_time FROM prescription p LEFT JOIN pet ON p.pet_id = pet.id WHERE p.is_deleted = 0
AND (p.prescription_no LIKE CONCAT('%', #{keyword}, '%') OR p.diagnosis LIKE CONCAT('%', #{keyword}, '%') OR pet.name LIKE CONCAT('%', #{keyword}, '%'))
AND p.doctor_id = #{doctorId}
AND p.pet_id = #{petId}
AND p.status = #{status}
ORDER BY p.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM prescription p
LEFT JOIN pet ON p.pet_id = pet.id
WHERE p.is_deleted = 0

    AND (p.prescription_no LIKE CONCAT('%', #{keyword}, '%')
        OR p.diagnosis LIKE CONCAT('%', #{keyword}, '%')
        OR pet.name LIKE CONCAT('%', #{keyword}, '%'))


    AND p.doctor_id = #{doctorId}


    AND p.pet_id = #{petId}


